{
  "type": "DRAG_FILL",
  "lessonText": "Challenge your cooking skills by applying what you've learned.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks to complete the recipe.",
        "codeTemplate": "To make a simple salad, you need ___, ___, and ___.",
        "options": [
          "lettuce",
          "tomatoes",
          "cucumbers",
          "dressing"
        ],
        "correctAnswer": "lettuce,tomatoes,dressing",
        "explanation": "A simple salad typically includes a base like lettuce, some vegetables like tomatoes, and a dressing."
      },
      {
        "instruction": "Complete the cooking steps.",
        "codeTemplate": "First, ___ the vegetables, then ___ them in a pan.",
        "options": [
          "chop",
          "boil",
          "fry",
          "season"
        ],
        "correctAnswer": "chop,fry",
        "explanation": "Chopping the vegetables is the first step, followed by frying them for cooking."
      },
      {
        "instruction": "Identify the ingredients needed.",
        "codeTemplate": "For a basic omelette, you need ___, ___, and ___.",
        "options": [
          "eggs",
          "milk",
          "cheese",
          "onions"
        ],
        "correctAnswer": "eggs,milk,cheese",
        "explanation": "A basic omelette requires eggs, a bit of milk for fluffiness, and cheese for flavor."
      },
      {
        "instruction": "Fill in the cooking method.",
        "codeTemplate": "To bake a cake, you must ___ the batter and ___ it in the oven.",
        "options": [
          "mix",
          "pour",
          "knead",
          "freeze"
        ],
        "correctAnswer": "mix,pour",
        "explanation": "Mixing the batter is essential before pouring it into the baking pan."
      }
    ]
  }
}
